import java.util.*;class P2{static int len(String s){int c=0;for(char ch:s.toCharArray())c++;return c;}static char[] uniq(String s){int n=len(s);char[] r=new char[n];int k=0;for(int i=0;i<n;i++){char c=s.charAt(i);boolean f=true;for(int j=0;j<i;j++)if(s.charAt(j)==c)f=false;if(f)r[k++]=c;}char[] u=new char[k];for(int i=0;i<k;i++)u[i]=r[i];return u;}public static void main(String[] a){Scanner s=new Scanner(System.in);String t=s.next();char[] u=uniq(t);for(char c:u)System.out.print(c+" ");}}